## React 中 State 与 Props 的区别

| 维度 | **Props** | **State** |
|------|-----------|-----------|
| **定义** | 父组件传递给子组件的**外部数据** | 组件内部自己管理的**私有数据** |
| **谁控制** | 父组件 | 当前组件自身 |
| **可修改** | ❌ **只读**，子组件不能修改 props | ✅ 可通过 `setState()` / `useState` 的 setter 修改 |
| **修改触发者** | 父组件重新渲染时传入新值 | 组件内部通过事件/副作用修改 |
| **用途** | 配置组件、传递回调、数据流向下 | 管理动态 UI 状态（表单、开关、加载态等） |
| **默认值** | `defaultProps` 或函数参数默认值 | `useState(initial)` 或 `this.state = {}` |
| **生命周期** | 父组件重新渲染时更新 | 改变时触发组件重新渲染 |

---

### 举个🌰

```jsx
// 父组件
function Parent() {
  const [count, setCount] = useState(0);   // ← state 在父组件

  return <Child count={count} onAdd={() => setCount(c => c + 1)} />;
}

// 子组件
function Child({ count, onAdd }) {          // ← props 从父组件来
  const [localMsg, setLocalMsg] = useState(''); // ← state 在子组件自己

  return (
    <div>
      <p>父传下来的 count: {count}</p>      {/* 只读，不能改 count */}
      <button onClick={onAdd}>+1</button>   {/* 通过回调通知父组件改 */}
      <input value={localMsg} onChange={e => setLocalMsg(e.target.value)} />
    </div>
  );
}
```

---

### 一句话记住

> **Props** 是父组件给子组件的**参数**（只读），**State** 是组件自己的**记忆**（可变）。

数据流向永远是 **单向**：父组件通过 props 向下流，子组件通过回调（也是 props 传下来的函数）向上通知。

我来为你写一个完整、健壮的 JavaScript debounce 函数，包含多种使用场景：

```javascript
/**
 * 创建一个防抖函数 (debounce)
 * 
 * @param {Function} fn - 需要防抖的函数
 * @param {number} delay - 延迟时间（毫秒）
 * @param {Object} [options] - 可选配置
 * @param {boolean} [options.leading=false] - 是否在延迟开始前立即执行一次
 * @param {boolean} [options.trailing=true] - 是否在延迟结束后执行（默认 true）
 * @param {number} [options.maxWait] - 最大等待时间，保证函数在此时间内至少执行一次
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true, maxWait } = options;

  let timer = null;
  let lastArgs = null;
  let lastThis = null;
  let lastCallTime = 0;
  let lastInvokeTime = 0;
  let maxing = typeof maxWait === 'number' && maxWait > 0;

  // 如果既不是 leading 也不是 trailing，则什么也不做
  if (!leading && !trailing) {
    return () => {};
  }

  function invokeFunc(time) {
    const args = lastArgs;
    const context = lastThis;

    lastArgs = lastThis = null;
    lastInvokeTime = time;

    fn.apply(context, args);
  }

  function startTimer(pendingFunc, wait) {
    return setTimeout(pendingFunc, wait);
  }

  function leadingEdge(time) {
    // 重置计时器
    timer = startTimer(timerExpired, delay);
    // 如果 leading 为 true，立即执行
    if (leading) {
      invokeFunc(time);
    }
  }

  function remainingWait(time) {
    const timeSinceLastCall = time - lastCallTime;
    const timeSinceLastInvoke = time - lastInvokeTime;
    const timeWaiting = delay - timeSinceLastCall;

    // 如果设置了 maxWait，取两者的最小值
    return maxing
      ? Math.min(timeWaiting, maxWait - timeSinceLastInvoke)
      : timeWaiting;
  }

  function shouldInvoke(time) {
    const timeSinceLastCall = time - lastCallTime;
    // 首次调用、超过延迟、系统时间被修改等情况下应执行
    return (
      lastCallTime === 0 ||
      timeSinceLastCall >= delay ||
      timeSinceLastCall < 0 ||
      (maxing && time - lastInvokeTime >= maxWait)
    );
  }

  function timerExpired() {
    const time = Date.now();
    // 检查是否应该执行 trailing 调用
    if (shouldInvoke(time)) {
      if (trailing) {
        invokeFunc(time);
      }
      timer = null;
      lastArgs = lastThis = null;
    } else {
      // 重新设置计时器
      timer = startTimer(timerExpired, remainingWait(time));
    }
  }

  function debounced(...args) {
    const time = Date.now();
    const isInvoking = shouldInvoke(time);

    lastArgs = args;
    lastThis = this;
    lastCallTime = time;

    if (isInvoking) {
      if (timer === null) {
        // leading edge 调用
        leadingEdge(time);
      } else if (maxing) {
        // 处理 maxWait 逻辑
        timer = startTimer(timerExpired, delay);
        if (trailing) {
          invokeFunc(time);
        }
      }
    }

    // 如果没有激活的计时器，创建一个
    if (timer === null) {
      timer = startTimer(timerExpired, delay);
    }
  }

  /**
   * 取消当前防抖调用
   */
  debounced.cancel = function () {
    if (timer !== null) {
      clearTimeout(timer);
    }
    timer = null;
    lastArgs = lastThis = null;
    lastCallTime = lastInvokeTime = 0;
  };

  /**
   * 立即执行并取消后续调用
   */
  debounced.flush = function () {
    if (timer !== null) {
      invokeFunc(Date.now());
      debounced.cancel();
    }
  };

  return debounced;
}
```

---

## 使用示例

### 1. 基本用法（trailing，默认）
```javascript
// 输入框搜索，用户停止输入 300ms 后触发
const searchInput = document.getElementById('search');
const handleSearch = debounce((e) => {
  console.log('搜索:', e.target.value);
}, 300);

searchInput.addEventListener('input', handleSearch);
```

### 2. leading（立即执行一次，然后防抖）
```javascript
// 按钮点击防抖，第一次立即执行，后续 500ms 内不再触发
const saveBtn = document.getElementById('save');
const handleSave = debounce(
  () => console.log('保存中...'),
  500,
  { leading: true, trailing: false }
);

saveBtn.addEventListener('click', handleSave);
```

### 3. leading + trailing（两端都执行）
```javascript
// 第一次立即执行，最后一次延迟后也执行
const handleResize = debounce(
  () => console.log('窗口大小变化'),
  300,
  { leading: true, trailing: true }
);

window.addEventListener('resize', handleResize);
```

### 4. maxWait（保证最大等待时间）
```javascript
// 无论触发多频繁，至少每 1000ms 执行一次
const handleScroll = debounce(
  () => console.log('滚动位置:', window.scrollY),
  200,
  { maxWait: 1000 }
);

window.addEventListener('scroll', handleScroll);
```

### 5. cancel / flush
```javascript
const debouncedFn = debounce(() => console.log('执行'), 1000);

debouncedFn();           // 开始计时
debouncedFn.cancel();    // 取消，不会执行

debouncedFn();           // 开始计时
debouncedFn.flush();     // 立即执行并取消后续
```

---

## 简化版（日常够用）

如果不需要 maxWait 和精细控制，一个简洁版就够了：

```javascript
function debounce(fn, delay, leading = false) {
  let timer = null;

  return function (...args) {
    const context = this;

    if (leading && timer === null) {
      fn.apply(context, args);
    }

    clearTimeout(timer);
    timer = setTimeout(() => {
      if (!leading) {
        fn.apply(context, args);
      }
      timer = null;
    }, delay);
  };
}
```

这个版本涵盖了 **搜索框防抖、按钮防重复点击、窗口 resize/scroll 优化** 等 90% 的日常场景。需要更精细控制时用上面的完整版。

